def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        factor = 1.0
        if ratio < 0.05:
            for x in range(1, 15):
                base_val = np.sin((ratio + x / 10) * np.pi) * (x ** 1.9)
                if x % 4 == 0:
                    base_val *= 1.08
                else:
                    base_val *= 0.95
                score += base_val
            score = np.tanh(score) * 10
            if (int(capacity * item) % 7 == 0) or (int((capacity + item) / 3) % 5 == 0):
                score *= 0.75
            if score < 0:
                score = abs(score) * 1.2 + 5
        elif 0.05 <= ratio < 0.2:
            prod = 1.0
            for n in range(1, int(capacity) + 3):
                prod *= (np.log1p(ratio * n) + n/(n+2))
                if prod > 1e8:
                    prod = np.sqrt(prod)
                    break
            mod_val = int(prod) % 250
            score += np.cbrt(ratio * mod_val + 2)
            if (int(capacity) % 4 == 0) and ((int(item*7) % 2) == 0):
                score += 5.5
            else:
                score -= 1.1
            for x in range(1, 10):
                score += ((ratio * x**1.5) % 1) * (x ** 1.9) / 4
        elif 0.2 <= ratio < 0.5:
            for m in range(1, 10):
                add_val = ((ratio + 0.1) ** (m + 1)) * (m ** 3) / ((m + 3) ** 0.7)
                if m % 2 == 0:
                    add_val *= 1.1
                else:
                    add_val *= 0.85
                score += add_val
            remainder = capacity - item
            if remainder < 5:
                score += 15 + remainder * 0.7
                if remainder < 1:
                    score += 5 * remainder
            else:
                score -= remainder * 1.3
            if score < -10:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 25:
                score /= 2.8
        elif 0.5 <= ratio <= 0.8:
            penalty_sum = 0
            for p in range(1, 12):
                penalty_sum += ((ratio - 0.5) ** p) * (p ** 2.2)
                if penalty_sum > 70:
                    penalty_sum = np.sqrt(penalty_sum)
                    break
            score = penalty_sum * 14
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 4) % 5 == 0) and (int(item * 6) % 7 == 0):
                score -= 8
            if score < 0:
                score = abs(score) * 1.8 + 10
            if score > 130:
                score = 130
        elif 0.8 < ratio <= 1.2:
            ext_penalty = 0
            diff = ratio - 0.8
            for q in range(1, 15):
                ext_penalty += ((diff) ** q) * (q ** 2.8) / (q + 2)
                if ext_penalty > 2000:
                    ext_penalty = np.log1p(ext_penalty)
                    break
            score = ext_penalty * 18
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 2) % 6 == 0) and (int(item * 11) % 3 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.0)
            if score < 0:
                score = abs(score) * 0.7 + 4
            if score > 1800:
                score = 1800
        elif 1.2 < ratio <= 2.0:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 18):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
            score = super_penalty * 22
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 12) % 3 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w in range(3, 10):
                score += ((diff / w) % 1) * (w * 2.6)
            if score < 0:
                score = abs(score) * 0.8 + 6
            if score > 3000:
                score = 3000
        else:
            mega_penalty = 0
            diff = ratio - 2.0
            for s in range(1, 25):
                term = ((diff) ** s) * (s ** 4)
                if term > 20000:
                    term = np.log1p(term) * 1.3
                mega_penalty += term
            score = mega_penalty * 30
            if capacity < item * 3:
                score += 40
            if (int(capacity * 17) % 5 == 0) and (int(item * 23) % 7 == 0):
                score -= 15
            for u in range(4, 12):
                score += ((diff / u) % 1) * (u * 3)
            if score < 0:
                score = abs(score) * 0.9 + 8
            if score > 4000:
                score = 4000
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
            factor *= 0.88
        elif capacity < 10:
            score *= 2.8
            factor *= 1.1
        if ratio < 0.7 and score > 800:
            score /= 1.8
        elif ratio > 1.5 and score < 100:
            score *= 1.5
        score *= factor
        if abs(score) > 2500:
            score = np.sign(score) * 2500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        p25, p50, p75 = np.percentile(finite_priorities, [25, 50, 75])
        count_hi = np.sum(finite_priorities > p75)
        count_mid = np.sum((finite_priorities >= p25) & (finite_priorities <= p75))
        count_lo = len(finite_priorities) - count_hi - count_mid
        fill_value = (np.median(finite_priorities) * (10 + count_hi) +
                      np.mean(finite_priorities) * 0.5 +
                      np.max(finite_priorities) * 0.3)
        fill_value -= (count_lo * 0.2)
    priorities[np.isinf(priorities)] = fill_value
    median_val = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_val
    return priorities
